\displaystyle{\begin{aligned}
   \frac{1}{6} + \frac{1}{10}
        \amp = \frac{5}{30} + \frac{3}{30} \\
        \amp = \frac{5 + 3}{30} \\
        \amp = \frac{8}{30} \amp \hbox{We can reduce this by dividing 2 into both the numerator and the denominator.
}\\
        \amp = \frac{4}{15}
\end{aligned}
    }
